import { useEffect, useRef, useState } from '@wordpress/element';
import SellerBadgeSelect from './SellerBadgeSelect';
import { Trophy } from 'lucide-react';
import { __ } from '@wordpress/i18n';

const SellerBadgeFilterField = ( {
    searchParams,
    setSearchParams,
} ) => {
    const [ sellerbadge, setSellerbadge ] = useState();
    const isFirstRender = useRef( true );

    // Initialize from URL if badge_id exists
    useEffect( () => {
        if ( typeof window === 'undefined' ) {
            return;
        }
        const badgeId = searchParams.get( 'badge_id' );
        if ( badgeId ) {
            // Set minimal value object; label can be hydrated by the select component
            setSellerbadge( badgeId );
        }
    }, [] );

    // Sync to URL and trigger filter on change (after first render)
    useEffect( () => {
        if ( isFirstRender.current ) {
            isFirstRender.current = false;
            return; // skip the first run
        }

        // @ts-ignore
        if ( sellerbadge && sellerbadge?.value ) {
            setSearchParams( ( prevParams ) => {
                // @ts-ignore
                prevParams.set( 'badge_id', sellerbadge.value );
                return prevParams;
            } );
        } else if ( sellerbadge && ! isNaN( Number( sellerbadge ) ) ) {
            setSearchParams( ( prevParams ) => {
                prevParams.set( 'badge_id', sellerbadge );
                return prevParams;
            } );
        } else {
            setSearchParams( ( prevParams ) => {
                prevParams.delete( 'badge_id' );
                return prevParams;
            } );
        }
    }, [ sellerbadge ] );

    return (
        <SellerBadgeSelect
            value={ sellerbadge }
            onChange={ setSellerbadge }
            icon={ <Trophy size="16" className="text-gray-500" /> }
            placeholder={ __( 'Search by Badge', 'dokan' ) }
            menuPortalTarget={ document.querySelector( 'body' ) }
        />
    );
};

export default SellerBadgeFilterField;
