import { useEffect, useRef, useState } from '@wordpress/element';
import apiFetch from '@wordpress/api-fetch';
import { addQueryArgs } from '@wordpress/url';
// @ts-ignore
// eslint-disable-next-line import/no-unresolved
import { Select } from '@dokan/components';
import { __ } from '@wordpress/i18n';

export interface SellerBadgeOption {
    value: number | string;
    label: string;
    raw?: any;
}

// Module-level cache to prevent refetch across unmounts/remounts
const sellerBadgeCache = new Map< string, SellerBadgeOption[] >();

const defaultMap = ( badge: any ): SellerBadgeOption => ( {
    value: badge?.id ?? badge?.ID ?? String( badge?.id ?? badge?.ID ?? '' ),
    label: badge?.badge_name,
    raw: badge,
} );

// Normalize a single primitive or option into SellerBadgeOption
const toOption = (
    input: SellerBadgeOption | string | number,
    opts: SellerBadgeOption[]
): SellerBadgeOption => {
    if (
        input &&
        typeof input === 'object' &&
        // @ts-ignore
        typeof ( input as any ).value !== 'undefined' &&
        // @ts-ignore
        typeof ( input as any ).label === 'string'
    ) {
        return input as SellerBadgeOption;
    }
    const found = opts.find(
        ( o ) => String( o.value ) === String( input as string | number )
    );
    return (
        found ?? {
            value: input as string | number,
            label: String( input ),
        }
    );
};

const normalizeValue = (
    value:
        | SellerBadgeOption
        | SellerBadgeOption[]
        | string
        | number
        | Array< string | number >
        | null
        | undefined,
    opts: SellerBadgeOption[]
): SellerBadgeOption | SellerBadgeOption[] | null | undefined => {
    if ( value === null || typeof value === 'undefined' ) {
        return value as null | undefined;
    }
    if ( Array.isArray( value ) ) {
        return ( value as Array< SellerBadgeOption | string | number > )
            .filter( ( v ) => typeof v !== 'undefined' && v !== null )
            .map( ( v ) => toOption( v as any, opts ) );
    }
    return toOption( value as any, opts );
};

function SellerBadgeSelect( props ) {
    const {
        endpoint = '/dokan/v1/seller-badge',
        mapOption = defaultMap,
        badgeStatus = 'all',
        perPage = -1,
        ...rest
    } = props;

    const [ options, setOptions ] = useState< SellerBadgeOption[] >( [] );
    const [ loaded, setLoaded ] = useState( false );
    const hasFetchedRef = useRef( false );

    useEffect( () => {
        let cancelled = false;
        ( async () => {
            if ( hasFetchedRef.current ) {
                return;
            }

            const cacheKey = JSON.stringify( {
                endpoint,
                badgeStatus,
                perPage,
            } );
            const cached = sellerBadgeCache.get( cacheKey );
            if ( cached ) {
                setOptions( cached );
                hasFetchedRef.current = true;
                setLoaded( true );
                return;
            }

            try {
                const path = addQueryArgs( endpoint, {
                    badge_status: badgeStatus,
                    per_page: perPage,
                } );
                const data = await apiFetch< any[] >( { path } );
                if ( cancelled ) {
                    return;
                }
                const mapped = Array.isArray( data )
                    ? data.map( ( b ) => mapOption( b ) )
                    : [];
                sellerBadgeCache.set( cacheKey, mapped );
                setOptions( mapped );
            } catch ( e ) {
                setOptions( [] );
            } finally {
                if ( ! cancelled ) {
                    hasFetchedRef.current = true;
                    setLoaded( true );
                }
            }
        } )();
        return () => {
            cancelled = true;
        };
    }, [] );

    // Ensure controlled values are present in options so the control can display them.
    useEffect( () => {
        const rawValue = ( rest as any )?.value as
            | SellerBadgeOption
            | SellerBadgeOption[]
            | string
            | number
            | Array< string | number >
            | null
            | undefined;
        if ( rawValue === null || typeof rawValue === 'undefined' ) {
            return;
        }
        setOptions( ( prev ) => {
            const base = Array.isArray( prev ) ? prev : [];
            const exists = ( v: SellerBadgeOption ) =>
                base.some( ( o ) => String( o.value ) === String( v.value ) );

            const ensure = ( input: any ) => {
                const option = toOption( input, base );
                return exists( option ) ? null : option;
            };

            if ( Array.isArray( rawValue ) ) {
                const add = rawValue
                    .map( ( v ) => ensure( v ) )
                    .filter( Boolean ) as SellerBadgeOption[];
                return add.length ? [ ...base, ...add ] : base;
            }
            const addOne = ensure( rawValue );
            if ( addOne ) {
                return [ ...base, addOne ];
            }
            return base;
        } );
    }, [ rest ] );

    const allOptions = options;

    // For SearchableSelect, we provide all options and let built-in filtering handle it.
    // If we need custom filtering, we could pass a filterOption prop, but defaults should suffice.

    // Stable instance id to avoid unnecessary remounts across parent re-renders
    const instanceIdRef = useRef(
        `seller-badge-${ Math.random().toString( 36 ).slice( 2 ) }`
    );

    const { onChange, value, ...restProps } = rest as any;
    const normalized = normalizeValue( value as any, options ) as
        | SellerBadgeOption
        | SellerBadgeOption[]
        | null
        | undefined;

    const handleChange = ( val: any ) => {
        // val will be SellerBadgeOption or array from the Select
        if ( typeof onChange === 'function' ) {
            onChange( val );
        }
    };

    return (
        <Select< SellerBadgeOption >
            options={ allOptions }
            isLoading={ ! loaded }
            instanceId={ instanceIdRef.current }
            value={ normalized as any }
            onChange={ handleChange as any }
            selectedTitle={ __( 'Badge', 'dokan' ) }
            { ...restProps }
        />
    );
}

export default SellerBadgeSelect;
