import { __ } from '@wordpress/i18n';
import SellerBadgeFilterField from './components/SellerBadgeFilterField';
// Ensure wp global exists at runtime
declare const wp: any;

if (
    typeof window !== 'undefined' &&
    ( window as any ).wp &&
    ( window as any ).wp.hooks
) {
    wp.hooks.addFilter(
        'dokan_admin_vendors_list_filters',
        'dokanVendor',
        ( fields ) => {
            fields.push( {
                id: 'badge_id',
                label: __( 'Seller Badge', 'dokan' ),
                field: SellerBadgeFilterField,
            } );
            // fields.push( SubscriptionFilterField );
            return fields;
        }
    );

    wp.hooks.addFilter(
        'dokan_admin_vendors_before_request',
        'dokanVendor',
        ( query, searchParams ) => {
            if ( searchParams.get( 'badge_id' ) ) {
                query.badge_id = searchParams.get( 'badge_id' );
            }

            return query;
        },
        10,
        3
    );

    wp.hooks.addFilter(
        'dokan_vendors_show_filters',
        'dokanVendor',
        ( query, searchParams ) => {
            if ( searchParams.get( 'badge_id' ) ) {
                return true;
            }

            return query;
        },
        10,
        2
    );
}
